import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as l,c as t,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation နှင့် Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"my/Safety/image-moderation-and-access-mode.md","filePath":"my/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),r={name:"my/Safety/image-moderation-and-access-mode.md"};function o(s,e,n,c,m,p){return l(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="image-moderation-နှင့်-access-mode" tabindex="-1">Image Moderation နှင့် Access Mode <a class="header-anchor" href="#image-moderation-နှင့်-access-mode" aria-label="Permalink to &quot;Image Moderation နှင့် Access Mode&quot;">​</a></h1><p>Image moderation က uploaded images တွေကို age ratings သတ်မှတ်ပေးပါတယ်။ Access mode က public access မှတစ်ဆင့် ဘယ် ratings တွေမြင်နိုင်မလဲထိန်းချုပ်ပါတယ်။</p><p>ဒါက public gallery, public file URLs, random image API တို့ကိုသက်ရောက်ပါတယ်။ admin panel ကိုတော့ကန့်သတ်မထားပါ။ Administrators တွေက files အားလုံးကို ဆက်မြင်ပြီး manage လုပ်နိုင်ပါတယ်။</p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>admin panel ကိုဖွင့်ပြီး သွားပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>main settings တွေ:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-က-ဘာလုပ်လဲ" tabindex="-1">Access Mode က ဘာလုပ်လဲ <a class="header-anchor" href="#access-mode-က-ဘာလုပ်လဲ" aria-label="Permalink to &quot;Access Mode က ဘာလုပ်လဲ&quot;">​</a></h2><p>Access mode က public မှာပြလို့ရတဲ့ age ratings ကိုဆုံးဖြတ်ပါတယ်။</p><p>လက်ရှိ modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>General only</td></tr></tbody></table><p>default က Adult mode ဖြစ်ပါတယ်။</p><p>private sites သို့မဟုတ် mature content ပါတဲ့ sites တွေအတွက် Adult mode သင့်တော်နိုင်ပါတယ်။ public gallery ကိုပိုထိန်းချင်လျှင် Youth, Teen, Child mode တို့ကိုရွေးပါ။</p><h2 id="moderation-enable-လုပ်ရင်-ဘာဖြစ်မလဲ" tabindex="-1">Moderation Enable လုပ်ရင် ဘာဖြစ်မလဲ <a class="header-anchor" href="#moderation-enable-လုပ်ရင်-ဘာဖြစ်မလဲ" aria-label="Permalink to &quot;Moderation Enable လုပ်ရင် ဘာဖြစ်မလဲ&quot;">​</a></h2><p>moderation enabled ဖြစ်လျှင် ImgBed က upload အချိန်မှာ selected moderation provider ကို call လုပ်ပြီး detected age rating ကိုသိမ်းပါမယ်။</p><p>main ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>public အတွက် safe ဖြစ်တဲ့ content</td></tr><tr><td>R12</td><td>အနည်းငယ် sensitive ဖြစ်တဲ့ content</td></tr><tr><td>R16</td><td>အလယ်အလတ် sensitive ဖြစ်တဲ့ content</td></tr><tr><td>R18</td><td>adult content</td></tr></tbody></table><p>public access ဆုံးဖြတ်တဲ့အခါ moderation result ကိုသုံးပါတယ်။</p><p>moderation enabled မဟုတ်လျှင်၊ သို့မဟုတ် old files တွေမှာ rating မရှိလျှင် အဲဒီ files တွေကို unrated အဖြစ်သတ်မှတ်ပါတယ်။ rating မရှိရုံနဲ့ unrated files တွေကို public gallery သို့မဟုတ် random image API မှအလိုအလျောက်မဖယ်ရှားပါ။</p><h2 id="moderation-provider-ရွေးချယ်ခြင်း" tabindex="-1">Moderation Provider ရွေးချယ်ခြင်း <a class="header-anchor" href="#moderation-provider-ရွေးချယ်ခြင်း" aria-label="Permalink to &quot;Moderation Provider ရွေးချယ်ခြင်း&quot;">​</a></h2><p>available providers:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>provider တစ်ခုချင်းစီရဲ့ requirements မတူပါ:</p><ul><li>moderatecontent.com က များသောအားဖြင့် API Key လိုပါတယ်။</li><li>nsfwjs က များသောအားဖြင့် API endpoint URL လိုပါတယ်။</li><li>Sightengine က API user နဲ့ API secret လိုပါတယ်။</li></ul><p>သင့် account, availability, detection quality အပေါ်မူတည်ပြီးရွေးပါ။ moderation enabled ဖြစ်ပြီးမှန်ကန်စွာ configured ဖြစ်လျှင် ImgBed က upload အချိန်မှာ image rating ရေးဖို့ကြိုးစားပါမယ်။</p><h2 id="public-gallery-အပေါ်-သက်ရောက်မှု" tabindex="-1">Public Gallery အပေါ် သက်ရောက်မှု <a class="header-anchor" href="#public-gallery-အပေါ်-သက်ရောက်မှု" aria-label="Permalink to &quot;Public Gallery အပေါ် သက်ရောက်မှု&quot;">​</a></h2><p>public gallery က access mode အတိုင်း files တွေကို filter လုပ်ပါတယ်။</p><p>ဥပမာ:</p><ul><li>Adult mode: R18 images ပေါ်နိုင်သည်။</li><li>Youth mode: R18 images ဖျောက်ထားသည်။</li><li>Teen mode: R16 နဲ့ R18 images ဖျောက်ထားသည်။</li><li>Child mode: General images ပဲပြသည်။</li></ul><p>ဒါက normal public access ကိုသာသက်ရောက်ပါတယ်။ admin panel က files အားလုံးကိုဆက်ပြပါတယ်။</p><h2 id="public-file-urls-အပေါ်-သက်ရောက်မှု" tabindex="-1">Public File URLs အပေါ် သက်ရောက်မှု <a class="header-anchor" href="#public-file-urls-အပေါ်-သက်ရောက်မှု" aria-label="Permalink to &quot;Public File URLs အပေါ် သက်ရောက်မှု&quot;">​</a></h2><p>Public file URLs ဆိုတာ visitors တွေဖွင့်တဲ့ direct image links ဖြစ်ပါတယ်။</p><p>file rating က current access mode မှာ allowed ဖြစ်လျှင် ImgBed က original image ကိုပြန်ပေးပါမယ်။</p><p>rating က allowed level ထက်မြင့်လျှင် normal public access က original image ကိုမပြန်ပေးပါ။ အစား configured blocked result သို့မဟုတ် blocked image အစားထိုးကိုပြန်ပေးပါမယ်။</p><p>ဥပမာ:</p><ul><li>current mode က Child mode ဖြစ်သည်။</li><li>image တစ်ခုက R18 rated ဖြစ်သည်။</li><li>visitor က public URL ကိုတိုက်ရိုက်ဖွင့်သည်။</li><li>ImgBed က အဲဒီ visitor ကို R18 original image မပြန်ပေးပါ။</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>admin panel ထဲက files ကြည့်နေတဲ့ administrators တွေက ဒီ restriction နဲ့မသက်ရောက်ပါ။</p><h2 id="random-image-api-အပေါ်-သက်ရောက်မှု" tabindex="-1">Random Image API အပေါ် သက်ရောက်မှု <a class="header-anchor" href="#random-image-api-အပေါ်-သက်ရောက်မှု" aria-label="Permalink to &quot;Random Image API အပေါ် သက်ရောက်မှု&quot;">​</a></h2><p>random image API လည်း candidate pool ကို access mode အတိုင်း filter လုပ်ပါတယ်။</p><p>Child mode မှာ random images တွေကို General-rated files ထဲကပဲရွေးပါမယ်။</p><p>Youth mode မှာ random images တွေက General, R12, R16 files ထဲကဖြစ်နိုင်ပြီး R18 files မပါပါ။</p><p>ဒါက random image API က public gallery restrictions ကို bypass မလုပ်နိုင်အောင်ကာကွယ်ပေးပါတယ်။</p><h2 id="list-rules-နဲ့ဆက်စပ်မှု" tabindex="-1">List Rules နဲ့ဆက်စပ်မှု <a class="header-anchor" href="#list-rules-နဲ့ဆက်စပ်မှု" aria-label="Permalink to &quot;List Rules နဲ့ဆက်စပ်မှု&quot;">​</a></h2><p>Access mode တစ်ခုတည်းက public access rule မဟုတ်ပါ။ allow/block list rules နဲ့အတူအလုပ်လုပ်ပါတယ်။</p><p>ရိုးရိုးပြောရရင်:</p><ul><li>Allowlisted content က အရင် public ဖြစ်ပါတယ်။</li><li>Blocklisted content ကို regular visitors တွေတိုက်ရိုက်မမြင်နိုင်ပါ။</li><li>list နှစ်ခုထဲမပါတဲ့ content ကို access mode နဲ့ထပ်စစ်ပါတယ်။</li></ul><p>image တစ်ခုက age rating နဲ့ list rules နှစ်မျိုးလုံးကြောင့် restricted ဖြစ်လျှင် regular visitors တွေက original file ကိုတိုက်ရိုက်မမြင်နိုင်ပါ။</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Public sites အတွက်:</p><ul><li>moderation enable လုပ်ပါ။</li><li>site audience နဲ့ကိုက်တဲ့ access mode ရွေးပါ။</li><li>all-age visitors အတွက် Child mode သို့မဟုတ် Teen mode သုံးပါ။</li><li>mature content ကို public မပြချင်လျှင် Adult mode ကိုရှောင်ပါ။</li><li>admin panel မှာ file ratings တွေကို review လုပ်ပြီးလိုအပ်လျှင် manually adjust လုပ်ပါ။</li></ul><p>Private သို့မဟုတ် personal sites အတွက်:</p><ul><li>Adult mode က များသောအားဖြင့် fine ဖြစ်ပါတယ်။</li><li>အသုံးဝင်လျှင် moderation enable လုပ်ပါ။</li><li>လိုအပ်သလို admin panel မှာ ratings review/adjust လုပ်ပါ။</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="access-mode-ပြောင်းပြီးနောက်-files-တွေ-admin-panel-ကနေပျောက်မလား" tabindex="-1">Access Mode ပြောင်းပြီးနောက် Files တွေ Admin Panel ကနေပျောက်မလား? <a class="header-anchor" href="#access-mode-ပြောင်းပြီးနောက်-files-တွေ-admin-panel-ကနေပျောက်မလား" aria-label="Permalink to &quot;Access Mode ပြောင်းပြီးနောက် Files တွေ Admin Panel ကနေပျောက်မလား?&quot;">​</a></h3><p>မပျောက်ပါ။</p><p>Access mode က normal public access ကိုသာသက်ရောက်ပါတယ်။ admin panel ကိုမသက်ရောက်ပါ။</p><h3 id="child-mode-ပြောင်းပြီးနောက်-public-gallery-မှာ-images-နည်းသွားတာဘာကြောင့်လဲ" tabindex="-1">Child Mode ပြောင်းပြီးနောက် Public Gallery မှာ Images နည်းသွားတာဘာကြောင့်လဲ? <a class="header-anchor" href="#child-mode-ပြောင်းပြီးနောက်-public-gallery-မှာ-images-နည်းသွားတာဘာကြောင့်လဲ" aria-label="Permalink to &quot;Child Mode ပြောင်းပြီးနောက် Public Gallery မှာ Images နည်းသွားတာဘာကြောင့်လဲ?&quot;">​</a></h3><p>Child mode က General-rated files တွေကိုသာ public ပြပါတယ်။ R12, R16, R18 files တွေကို filter လုပ်ပါတယ်။</p><h3 id="public-urls-က-adult-images-ကိုဖွင့်နိုင်လား" tabindex="-1">Public URLs က Adult Images ကိုဖွင့်နိုင်လား? <a class="header-anchor" href="#public-urls-က-adult-images-ကိုဖွင့်နိုင်လား" aria-label="Permalink to &quot;Public URLs က Adult Images ကိုဖွင့်နိုင်လား?&quot;">​</a></h3><p>current access mode က အဲဒီ rating ကို allow မလုပ်လျှင် normal public URLs က original image ကိုမပြန်ပေးပါ။</p><h3 id="random-image-api-က-restricted-images-ပြန်ပေးနိုင်လား" tabindex="-1">Random Image API က Restricted Images ပြန်ပေးနိုင်လား? <a class="header-anchor" href="#random-image-api-က-restricted-images-ပြန်ပေးနိုင်လား" aria-label="Permalink to &quot;Random Image API က Restricted Images ပြန်ပေးနိုင်လား?&quot;">​</a></h3><p>မပေးနိုင်ပါ။</p><p>random image API က candidates တွေကို current access mode အတိုင်း filter လုပ်ပါတယ်။</p><h3 id="old-unrated-images-တွေဘာဖြစ်မလဲ" tabindex="-1">Old Unrated Images တွေဘာဖြစ်မလဲ? <a class="header-anchor" href="#old-unrated-images-တွေဘာဖြစ်မလဲ" aria-label="Permalink to &quot;Old Unrated Images တွေဘာဖြစ်မလဲ?&quot;">​</a></h3><p>unrated images တွေက moderation results မရှိတာကြောင့်ပဲ အလိုအလျောက် hidden မဖြစ်ပါ။ နောက်ပိုင်း admin panel ထဲမှာ သူတို့ရဲ့ ratings ကို adjust လုပ်နိုင်ပါတယ်။</p>',67)])])}const b=i(r,[["render",o]]);export{h as __pageData,b as default};
